	ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel()

	res, err := slowOp(ctx)
	if err != nil {
		fmt.Println("operation failed:", err)
		return
	}
	fmt.Println("operation result:", res)
